Функция бинарного поиска применяется к отсортированному списку a = [1, 3, 5, 7, 9, 11, 13]. С каким элементом списка произойдёт ПЕРВОЕ сравнение при поиске значения 9?

def bsearch(a, target):
    lo, hi = 0, len(a) - 1
    while lo <= hi:
        mid = (lo + hi) // 2
        if a[mid] == target:
            return mid
        elif a[mid] < target:
            lo = mid + 1
        else:
            hi = mid - 1
    return -1
